2	import type { PluginPackageChannel } from "../plugins/manifest.js";
3	import { CHAT_CHANNEL_ORDER, type ChatChannelId } from "./ids.js";
4	import type { ChannelMeta } from "./plugins/types.js";
5	
6	export type ChatChannelMeta = ChannelMeta;
7	
8	const CHAT_CHANNEL_ID_SET = new Set<string>(CHAT_CHANNEL_ORDER);
9	
10	function toChatChannelMeta(params: {
11	  id: ChatChannelId;
12	  channel: PluginPackageChannel;
13	}): ChatChannelMeta {
14	  const label = params.channel.label?.trim();
15	  if (!label) {
16	    throw new Error(`Missing label for bundled chat channel "${params.id}"`);
17	  }
18	
19	  return {
20	    id: params.id,
