import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin, getChatChannelMeta } from "openclaw/plugin-sdk/core";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import type { PulseBoardAccount } from "./types.js";

/** Minimal resolved account shape used throughout the PulseBoard plugin. */
type ResolvedPulseBoardAccount = PulseBoardAccount & {
  accountId: string;
  configured: boolean;
};

// "pulseboard" is not a registered core channel ID; type-cast to satisfy the SDK
// parameter type so we follow the standard plugin-SDK meta pattern.
const registeredMeta = getChatChannelMeta(
  "pulseboard" as Parameters<typeof getChatChannelMeta>[0],
);

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      // Spread whatever the registry may return for a future registered entry,
      // then assert the PulseBoard-specific values so they are always present.
      ...registeredMeta,
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin)",
      docsPath: "/channels/pulseboard",
      blurb: "Connect to PulseBoard bulletin board messaging.",
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: () => [],
      resolveAccount: (_cfg, accountId) => ({
        accountId: accountId ?? "default",
        configured: false,
        boardUrl: "",
        apiToken: "",
        username: "",
      }),
      isConfigured: () => false,
    },
    setup: {
      resolveAccountId: ({ accountId }) => accountId ?? "default",
      applyAccountConfig: ({ cfg }) => cfg, // stub: config unchanged until real setup is wired up
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(
          `[${ctx.accountId}] connecting to PulseBoard at ${ctx.account.boardUrl}`,
        );
      },
    },
    messaging: {
      normalizeTarget: (target) => target.trim(),
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to }) => {
      // Stub: in a real implementation this would POST to the PulseBoard API.
      return attachChannelToResult("pulseboard", {
        to,
        messageId: `pulseboard-${Date.now()}`,
      });
    },
  },
});

